export const themeFiles: Record<string, string> = {
  "classic/templates/products": "<div class=\"min-h-screen\">\r\n  <div class=\"max-w-6xl mx-auto px-8 py-12\">\r\n    {{- - HEADER - -}}\r\n    <div class=\"text-center mb-12\">\r\n      <h1 class=\"sf-heading text-4xl md:text-5xl font-light tracking-tight mb-8\">All Products</h1>\r\n\r\n      {{- - SEARCH - -}}\r\n      <div class=\"max-w-xl mx-auto relative\">\r\n        <svg\r\n          class=\"absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4\"\r\n          viewBox=\"0 0 24 24\"\r\n          fill=\"none\"\r\n          stroke=\"currentColor\"\r\n          stroke-width=\"2\"\r\n          stroke-linecap=\"round\"\r\n          stroke-linejoin=\"round\"\r\n          style=\"color: var(--sf-foreground); opacity: 0.38\"\r\n        >\r\n          {% raw %}<circle cx=\"11\" cy=\"11\" r=\"8\"/><path d=\"m21 21-4.35-4.35\"/>{% endraw %}\r\n        </svg>\r\n        <input\r\n          id=\"sf-search\"\r\n          type=\"text\"\r\n          placeholder=\"Search products...\"\r\n          autocomplete=\"off\"\r\n          class=\"sf-input w-full pl-11 pr-10 h-11 text-sm border\"\r\n          style=\"\r\n            background: var(--sf-background); color: var(--sf-foreground);\r\n            border-color: var(--sf-border); border-radius: var(--sf-border-radius)\r\n          \"\r\n        >\r\n        <button\r\n          id=\"sf-search-clear\"\r\n          class=\"absolute right-3 top-1/2 -translate-y-1/2 hidden\"\r\n          style=\"color: var(--sf-foreground); opacity: 0.5\"\r\n          aria-label=\"Clear search\"\r\n        >\r\n          <svg\r\n            width=\"14\"\r\n            height=\"14\"\r\n            viewBox=\"0 0 24 24\"\r\n            fill=\"none\"\r\n            stroke=\"currentColor\"\r\n            stroke-width=\"2\"\r\n            stroke-linecap=\"round\"\r\n            stroke-linejoin=\"round\"\r\n          >\r\n            {% raw %}<path d=\"M18 6 6 18M6 6l12 12\"/>{% endraw %}\r\n          </svg>\r\n        </button>\r\n      </div>\r\n      <p\r\n        id=\"sf-search-count\"\r\n        class=\"text-sm mt-3 hidden\"\r\n        style=\"color: var(--sf-foreground-subtle)\"\r\n      ></p>\r\n    </div>\r\n\r\n    {{- - EMPTY STATE - -}}\r\n    {%- if products == empty or products.size == 0 -%}\r\n      <div class=\"text-center py-20 space-y-3\">\r\n        <svg\r\n          class=\"mx-auto\"\r\n          width=\"40\"\r\n          height=\"40\"\r\n          viewBox=\"0 0 24 24\"\r\n          fill=\"none\"\r\n          stroke=\"currentColor\"\r\n          stroke-width=\"1.5\"\r\n          style=\"color: var(--sf-foreground); opacity: 0.2\"\r\n        >\r\n          {% raw %}\r\n          <path d=\"M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z\"/>\r\n          <path d=\"M3 6h18\"/>\r\n          <path d=\"M16 10a4 4 0 0 1-8 0\"/>\r\n          {% endraw %}\r\n        </svg>\r\n        <p class=\"sf-heading text-xl font-light\">No products yet</p>\r\n        <p class=\"text-sm\" style=\"color: var(--sf-foreground-subtle)\">Check back soon for new arrivals</p>\r\n      </div>\r\n\r\n    {%- else -%}\r\n      {{- - GRID - -}}\r\n      <div\r\n        id=\"sf-products-grid\"\r\n        class=\"grid gap-6 grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4\"\r\n      >\r\n        {%- for product in products -%}\r\n          {%- assign image = product.images[0] -%}\r\n          {%- assign in_stock = true -%}\r\n          {%- if product.track_inventory == true and product.inventory_quantity <= 0 -%}\r\n            {%- assign in_stock = false -%}\r\n          {%- endif -%}\r\n          {%- assign has_discount = false -%}\r\n          {%- if product.compare_at_price and product.compare_at_price > product.price -%}\r\n            {%- assign has_discount = true -%}\r\n          {%- endif -%}\r\n\r\n          <article\r\n            class=\"sf-card sf-product-card group overflow-hidden h-full flex flex-col py-0 sf-animate-fadein\"\r\n            data-name=\"{{ product.name | downcase }}\"\r\n            data-description=\"{{ product.description | strip_html | downcase | truncate: 200 }}\"\r\n          >\r\n            {{- - IMAGE - -}}\r\n            <div class=\"relative overflow-hidden aspect-[4/5] sf-bg-muted\">\r\n              {{- - WISHLIST ISLAND - -}}\r\n              <div\r\n                class=\"absolute top-2 right-2 z-10\"\r\n                data-wishlist-island\r\n                data-product-id=\"{{ product.id }}\"\r\n                data-store-id=\"{{ store.id }}\"\r\n              ></div>\r\n\r\n              <a href=\"/store/{{ store.slug }}/{{ product.slug }}\" class=\"block w-full h-full\">\r\n                {%- if image -%}\r\n                  <img\r\n                    src=\"{{ image }}\"\r\n                    alt=\"{{ product.name }}\"\r\n                    loading=\"lazy\"\r\n                    class=\"object-cover group-hover:scale-105 transition-transform duration-500 w-full h-full\"\r\n                  >\r\n                {%- else -%}\r\n                  <div class=\"w-full h-full flex items-center justify-center\">\r\n                    <svg\r\n                      width=\"32\"\r\n                      height=\"32\"\r\n                      viewBox=\"0 0 24 24\"\r\n                      fill=\"none\"\r\n                      stroke=\"currentColor\"\r\n                      stroke-width=\"1.5\"\r\n                      style=\"color: var(--sf-foreground); opacity: 0.2\"\r\n                    >\r\n                      {% raw %}\r\n                      <path d=\"M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z\"/>\r\n                      <path d=\"M3 6h18\"/>\r\n                      <path d=\"M16 10a4 4 0 0 1-8 0\"/>\r\n                      {% endraw %}\r\n                    </svg>\r\n                  </div>\r\n                {%- endif -%}\r\n              </a>\r\n\r\n              {%- if has_discount and in_stock -%}\r\n                {%- assign price_diff = product.compare_at_price | minus: product.price -%}\r\n                {%- assign discount_pct = price_diff | times: 100 | divided_by: product.compare_at_price | round -%}\r\n                <span class=\"sf-badge-sale absolute top-3 left-3 z-10 inline-flex items-center px-2.5 py-0.5 text-xs font-medium\">\r\n                  -{{ discount_pct }}%\r\n                </span>\r\n              {%- endif -%}\r\n\r\n              {%- if in_stock == false -%}\r\n                <div class=\"absolute inset-0 sf-bg-sold-out flex items-center justify-center z-10\">\r\n                  <span class=\"text-white font-medium text-sm\">Sold Out</span>\r\n                </div>\r\n              {%- endif -%}\r\n            </div>\r\n\r\n            {{- - CONTENT - -}}\r\n            <div class=\"pt-4 pb-6 px-4 flex-1 flex flex-col\">\r\n              <div class=\"space-y-1 mb-4 flex-1\">\r\n                <a href=\"/store/{{ store.slug }}/{{ product.slug }}\" class=\"block\">\r\n                  <h3\r\n                    class=\"sf-heading text-base font-normal leading-tight line-clamp-2 group-hover:underline\"\r\n                    style=\"color: var(--sf-foreground)\"\r\n                  >\r\n                    {{ product.name }}\r\n                  </h3>\r\n                </a>\r\n                {%- if product.description -%}\r\n                  <p\r\n                    class=\"text-xs line-clamp-2\"\r\n                    style=\"color: var(--sf-foreground-subtle)\"\r\n                  >\r\n                    {{ product.description | strip_html | truncate: 120 }}\r\n                  </p>\r\n                {%- endif -%}\r\n              </div>\r\n\r\n              <div\r\n                class=\"flex flex-col gap-3\"\r\n                style=\"border-top: 1px solid var(--sf-border); padding-top: 1rem\"\r\n              >\r\n                <div class=\"flex items-end justify-between\">\r\n                  <div class=\"space-y-0.5\">\r\n                    <div class=\"text-base font-light\" style=\"color: var(--sf-foreground)\">\r\n                      {{ product.price | money: store.currency }}\r\n                    </div>\r\n                    {%- if has_discount -%}\r\n                      <div class=\"text-xs line-through\" style=\"color: var(--sf-foreground-subtle)\">\r\n                        {{ product.compare_at_price | money: store.currency }}\r\n                      </div>\r\n                    {%- endif -%}\r\n                  </div>\r\n\r\n                  {{- - CART ISLAND - -}}\r\n                  <div\r\n                    data-cart-island\r\n                    data-product-id=\"{{ product.id }}\"\r\n                    data-product-name=\"{{ product.name }}\"\r\n                    data-product-price=\"{{ product.price }}\"\r\n                    data-product-image=\"{{ image }}\"\r\n                    data-in-stock=\"{{ in_stock }}\"\r\n                  ></div>\r\n                </div>\r\n\r\n                <div\r\n                  class=\"flex items-center justify-between text-xs\"\r\n                  style=\"color: var(--sf-foreground-subtle)\"\r\n                >\r\n                  {%- if in_stock and product.track_inventory and product.inventory_quantity -%}\r\n                    <span class=\"flex items-center gap-1\">\r\n                      <svg\r\n                        width=\"10\"\r\n                        height=\"10\"\r\n                        viewBox=\"0 0 24 24\"\r\n                        fill=\"none\"\r\n                        stroke=\"currentColor\"\r\n                        stroke-width=\"2\"\r\n                      >\r\n                        {% raw %}<path d=\"M13 2L3 14h9l-1 8 10-12h-9l1-8z\"/>{% endraw %}\r\n                      </svg>\r\n                      {{ product.inventory_quantity }} in stock\r\n                    </span>\r\n                  {%- endif -%}\r\n                </div>\r\n              </div>\r\n            </div>\r\n          </article>\r\n        {%- endfor -%}\r\n      </div>\r\n\r\n      {{- - COUNT - -}}\r\n      <p\r\n        id=\"sf-products-count\"\r\n        class=\"text-sm text-center mt-10\"\r\n        style=\"color: var(--sf-foreground-subtle)\"\r\n      >\r\n        Showing <span style=\"color: var(--sf-foreground)\">{{ products.size }}</span> products\r\n      </p>\r\n    {%- endif -%}\r\n  </div>\r\n\r\n  <script>\r\n    (function () {\r\n      var input = document.getElementById('sf-search');\r\n      var clear = document.getElementById('sf-search-clear');\r\n      var count = document.getElementById('sf-search-count');\r\n      var totalCount = document.getElementById('sf-products-count');\r\n      var cards = document.querySelectorAll('#sf-products-grid article');\r\n      var total = cards.length;\r\n      var t;\r\n\r\n      if (input) {\r\n        input.addEventListener('input', function () {\r\n          clearTimeout(t);\r\n          t = setTimeout(function () {\r\n            filter(input.value);\r\n          }, 300);\r\n          clear.classList.toggle('hidden', !input.value);\r\n        });\r\n      }\r\n\r\n      if (clear) {\r\n        clear.addEventListener('click', function () {\r\n          input.value = '';\r\n          clear.classList.add('hidden');\r\n          filter('');\r\n        });\r\n      }\r\n\r\n      function filter(q) {\r\n        q = q.toLowerCase().trim();\r\n        var visible = 0;\r\n        cards.forEach(function (card) {\r\n          var name = card.dataset.name || '';\r\n          var desc = card.dataset.description || '';\r\n          var match = !q || name.includes(q) || desc.includes(q);\r\n          card.style.display = match ? '' : 'none';\r\n          if (match) visible++;\r\n        });\r\n        if (count) {\r\n          if (q) {\r\n            count.textContent = visible + ' ' + (visible === 1 ? 'result' : 'results') + ' for \"' + q + '\"';\r\n            count.classList.remove('hidden');\r\n          } else {\r\n            count.classList.add('hidden');\r\n          }\r\n        }\r\n        if (totalCount) {\r\n          totalCount.innerHTML =\r\n            'Showing <span style=\"color:var(--sf-foreground)\">' +\r\n            visible +\r\n            '</span> of <span style=\"color:var(--sf-foreground)\">' +\r\n            total +\r\n            '</span> products';\r\n        }\r\n      }\r\n\r\n      // fade-in observer\r\n      var els = document.querySelectorAll('.sf-animate-fadein');\r\n      if (els.length) {\r\n        var io = new IntersectionObserver(\r\n          function (entries) {\r\n            entries.forEach(function (e) {\r\n              if (e.isIntersecting) {\r\n                e.target.classList.add('sf-visible');\r\n                io.unobserve(e.target);\r\n              }\r\n            });\r\n          },\r\n          { threshold: 0.08 }\r\n        );\r\n        els.forEach(function (el) {\r\n          io.observe(el);\r\n        });\r\n      }\r\n    })();\r\n  </script>\r\n</div>\r\n",
  "classic/snippets/record-anchor": "{%- comment -%}\r\n  Marks a repeated record's CONTAINER element as a hover target for the Editor's\r\n  structural overlay (add/delete/reorder/duplicate). Field-level editability is\r\n  handled separately by editable-item; this marks the record as a whole.\r\n  Editor-only: a visitor receives none of these attributes.\r\n  Usage on the record's outer element inside a {% for %}:\r\n    <article {% render 'classic/snippets/record-anchor', editing: store.editing, list: 'programs', index: forloop.index0 %}>\r\n{%- endcomment -%}\r\n{%- if editing -%}data-mcloud-record=\"1\" data-mcloud-list=\"{{ list }}\" data-mcloud-index=\"{{ index }}\"{%- endif -%}\r\n",
  "classic/snippets/editable": "{%- comment -%}\r\n  Marks a rendered value as click-to-editable in the Editor's preview.\r\n\r\n  Usage:\r\n    <h2 {% render 'classic/snippets/editable', field: 'heading', value: section.heading %}>\r\n      {{ heading }}\r\n    </h2>\r\n\r\n  It emits the STORED value, not the rendered one, and that distinction is the\r\n  whole point.\r\n\r\n  Every heading renders through `| default: 'Support a Cause'`, so a section with\r\n  no stored heading still SHOWS one. If the Editor read the rendered text back out\r\n  of the DOM, then merely clicking into a heading and clicking away would save\r\n  \"Support a Cause\" as if the merchant had typed it: the default would be baked in\r\n  permanently and the fallback would be dead. The merchant would have no way to get\r\n  it back.\r\n\r\n  So the element carries data-mcloud-stored=\"\" for an unset field, and the Editor\r\n  diffs against THAT, never against textContent. Blank means blank.\r\n\r\n  Inert outside the preview: nothing styles or scripts these attributes on the\r\n  public site.\r\n{%- endcomment -%}\r\n{%- comment -%}\r\n  Emits NOTHING outside the editor: these attributes carry the merchant's stored\r\n  copy, and a visitor has no business receiving it.\r\n{%- endcomment -%}\r\n{%- if editing -%}data-mcloud-field=\"{{ field }}\" data-mcloud-stored=\"{{ value | escape }}\"{%- endif -%}\r\n",
  "classic/snippets/editable-setting": "{%- comment -%}\r\n  Marks a value that lives in stores.settings (NOT in the section's own config) as\r\n  click-to-editable.\r\n\r\n  Usage:\r\n    <h1 {% render 'classic/snippets/editable-setting', key: 'heroTitle', value: settings.heroTitle %}>\r\n      {{ slide_title }}\r\n    </h1>\r\n\r\n  Two editable channels exist because there are two places copy is stored, and they\r\n  save through different actions:\r\n\r\n    editable          -> pages.sections[i].settings   -> updatePageSections\r\n    editable-setting  -> stores.settings              -> updateStoreSettings\r\n\r\n  Same rule as `editable`: it emits the STORED value, never the rendered one. A\r\n  hero with no heroTitle falls back to store.name, so the DOM shows a title while\r\n  the setting is empty. Reporting the rendered text would silently freeze that\r\n  fallback into the record the first time anyone clicked it.\r\n{%- endcomment -%}\r\n{%- comment -%}\r\n  Emits NOTHING outside the editor: these attributes carry the merchant's stored\r\n  copy, and a visitor has no business receiving it.\r\n{%- endcomment -%}\r\n{%- if editing -%}data-mcloud-setting=\"{{ key }}\" data-mcloud-stored=\"{{ value | escape }}\"{%- endif -%}\r\n",
  "classic/snippets/editable-item": "{%- comment -%}\r\n  Marks a field inside a REPEATED record in stores.settings (programs[2].title,\r\n  campaigns[0].description, impactStats[1].value …) as click-to-editable.\r\n\r\n  Usage, inside a {% for %} with forloop available:\r\n    <h3 {% render 'classic/snippets/editable-item',\r\n          list: 'programs', index: forloop.index0, key: 'title', value: program.title %}>\r\n      {{ program.title }}\r\n    </h3>\r\n\r\n  The list name and the index are BOTH required: without them an edit cannot say\r\n  which record it belongs to, and the admin would have to guess — which is how you\r\n  overwrite the wrong programme.\r\n\r\n  Editing an existing record's text is all this covers. Adding, removing and\r\n  reordering records stay in the drawer, because there is no text on the page to\r\n  click for a record that does not exist yet.\r\n{%- endcomment -%}\r\n{%- comment -%}\r\n  Emits NOTHING outside the editor: these attributes carry the merchant's stored\r\n  copy, and a visitor has no business receiving it.\r\n{%- endcomment -%}\r\n{%- if editing -%}data-mcloud-list=\"{{ list }}\" data-mcloud-index=\"{{ index }}\" data-mcloud-key=\"{{ key }}\" data-mcloud-stored=\"{{ value | escape }}\"{%- endif -%}\r\n",
  "classic/snippets/editable-image": "{%- comment -%}\r\n  Marks an image as click-to-replace in the Editor's preview.\r\n\r\n  Usage (a store setting):\r\n    {% render 'classic/snippets/editable-image', setting: 'heroImage', value: settings.heroImage %}\r\n\r\n  Usage (a field on a repeated record):\r\n    {% render 'classic/snippets/editable-image',\r\n       list: 'programs', index: forloop.index0, key: 'image', value: program.image %}\r\n\r\n  Emits the same addressing attributes the TEXT snippets do, so the bridge routes an\r\n  image change through the exact channels that already exist (setting-edit /\r\n  item-edit). An image is just a string field whose editor is a picker rather than a\r\n  caret — no new save path, no new server action.\r\n\r\n  data-mcloud-image is what tells the bridge to open a picker instead of making the\r\n  element contentEditable. Editing text in an <img> is meaningless; the two\r\n  affordances have to differ even though the storage does not.\r\n{%- endcomment -%}\r\n{%- comment -%}\r\n  Emits NOTHING outside the editor. The hero's background always renders (it is the\r\n  page's backdrop, not an optional affordance), so without this guard every visitor\r\n  would be served editor scaffolding on the live site. Inert, but it has no business\r\n  being there — and the text snippets are already effectively gated, because the\r\n  elements they mark only render for a visitor when they have content.\r\n{%- endcomment -%}\r\n{%- if editing -%}\r\ndata-mcloud-image=\"1\"\r\n{%- if setting %} data-mcloud-setting=\"{{ setting }}\"{% endif -%}\r\n{%- if list %} data-mcloud-list=\"{{ list }}\" data-mcloud-index=\"{{ index }}\" data-mcloud-key=\"{{ key }}\"{% endif -%}\r\n{{ ' ' }}data-mcloud-stored=\"{{ value | escape }}\"\r\n{%- endif -%}\r\n",
  "classic/sections/programs": "{%- assign heading = section.heading | default: 'What We Do' -%}\r\n{%- assign eyebrow = section.eyebrow | default: 'Programs' -%}\r\n{%- assign settings = store.settings -%}\r\n{%- assign programs = null -%}\r\n{%- if settings -%}{%- assign programs = settings.programs -%}{%- endif -%}\r\n{%- if programs and programs.size > 0 -%}\r\n<section class=\"sf-programs py-16 md:py-24\">\r\n  <div class=\"container mx-auto max-w-6xl px-6\">\r\n    <div class=\"mb-10 md:mb-14 text-center\">\r\n      <span class=\"sf-badge-outline inline-flex items-center border px-2.5 py-0.5 text-xs font-medium mb-3\" {% render 'classic/snippets/editable', editing: store.editing, field: 'eyebrow', value: section.eyebrow %}>\r\n        {{ eyebrow }}\r\n      </span>\r\n      <h2 class=\"sf-heading text-3xl md:text-4xl font-light tracking-tight\" {% render 'classic/snippets/editable', editing: store.editing, field: 'heading', value: section.heading %}>{{ heading }}</h2>\r\n    </div>\r\n    <div class=\"grid gap-6 md:gap-8\" style=\"grid-template-columns: repeat(auto-fill, minmax(280px, 1fr))\">\r\n      {%- for program in programs -%}\r\n        <article class=\"sf-card sf-program-card overflow-hidden\" {% render 'classic/snippets/record-anchor', editing: store.editing, list: 'programs', index: forloop.index0 %}>\r\n          {%- comment -%}\r\n            Liquid treats \"\" as truthy, so a blank image field would render\r\n            <img src=\"\"> and the browser draws a broken image. Compare against\r\n            empty explicitly.\r\n          {%- endcomment -%}\r\n          {%- if program.image and program.image != '' -%}\r\n            <div class=\"relative overflow-hidden sf-bg-muted\" style=\"aspect-ratio: 16/9\"\r\n              {% render 'classic/snippets/editable-image', editing: store.editing, list: 'programs', index: forloop.index0, key: 'image', value: program.image %}>\r\n              <img src=\"{{ program.image }}\" alt=\"{{ program.title }}\" loading=\"lazy\" class=\"absolute inset-0 w-full h-full object-cover\">\r\n            </div>\r\n          {%- elsif store.editing -%}\r\n            {%- comment -%}\r\n              No image yet. A visitor sees nothing at all (as before), but the editor\r\n              needs a real, sized target to click, or there is no way to ADD one.\r\n            {%- endcomment -%}\r\n            <div class=\"relative overflow-hidden sf-bg-muted\" style=\"aspect-ratio: 16/9\"\r\n              {% render 'classic/snippets/editable-image', editing: store.editing, list: 'programs', index: forloop.index0, key: 'image', value: program.image %}></div>\r\n          {%- endif -%}\r\n          <div class=\"px-4 pt-4 pb-4 space-y-1\">\r\n            <h3 class=\"sf-heading text-xl font-light\" {% render 'classic/snippets/editable-item', editing: store.editing, list: 'programs', index: forloop.index0, key: 'title', value: program.title %}>{{ program.title }}</h3>\r\n            {%- if program.description or store.editing -%}\r\n              <p class=\"text-sm\" style=\"color: var(--sf-foreground-subtle)\" {% render 'classic/snippets/editable-item', editing: store.editing, list: 'programs', index: forloop.index0, key: 'description', value: program.description %}>{{ program.description }}</p>\r\n            {%- endif -%}\r\n          </div>\r\n        </article>\r\n      {%- endfor -%}\r\n    </div>\r\n  </div>\r\n</section>\r\n{%- endif -%}\r\n",
  "classic/sections/product-card": "{%- assign in_stock = true -%}\r\n{%- if product.track_inventory == true and product.inventory_quantity <= 0 -%}\r\n  {%- assign in_stock = false -%}\r\n{%- endif -%}\r\n\r\n{%- assign has_discount = false -%}\r\n{%- if product.compare_at_price and product.compare_at_price > product.price -%}\r\n  {%- assign has_discount = true -%}\r\n{%- endif -%}\r\n\r\n{%- assign image = product.images[0] -%}\r\n\r\n<a\r\n  href=\"/store/{{ store.slug }}/{{ product.slug }}\"\r\n  class=\"sf-product-card-link group block sf-animate-fadein\"\r\n>\r\n  <article class=\"sf-card sf-product-card overflow-hidden cursor-pointer h-full flex flex-col\">\r\n    {{- - IMAGE ZONE - -}}\r\n    <div class=\"relative overflow-hidden sf-bg-muted sf-product-card__image-wrap\">\r\n      {%- if image -%}\r\n        <img\r\n          src=\"{{ image }}\"\r\n          alt=\"{{ product.name }}\"\r\n          loading=\"lazy\"\r\n          class=\"sf-product-card__image w-full h-full object-cover\"\r\n        >\r\n      {%- else -%}\r\n        <div class=\"sf-product-card__placeholder w-full h-full flex items-center justify-center\">\r\n          <svg\r\n            class=\"sf-product-card__bag-icon\"\r\n            viewBox=\"0 0 24 24\"\r\n            fill=\"none\"\r\n            stroke=\"currentColor\"\r\n            stroke-width=\"1.5\"\r\n            stroke-linecap=\"round\"\r\n            stroke-linejoin=\"round\"\r\n          >\r\n            {% raw %}\r\n            <path d=\"M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z\"/>\r\n            <path d=\"M3 6h18\"/>\r\n            <path d=\"M16 10a4 4 0 0 1-8 0\"/>\r\n            {% endraw %}\r\n          </svg>\r\n        </div>\r\n      {%- endif -%}\r\n\r\n      {{- - QUICK VIEW OVERLAY - -}}\r\n      <div class=\"sf-product-card__overlay absolute inset-0 flex items-center justify-center\">\r\n        <span class=\"sf-product-card__quick-view\">View product</span>\r\n      </div>\r\n\r\n      {{- - OUT OF STOCK - -}}\r\n      {%- if in_stock == false -%}\r\n        <div class=\"sf-product-card__oos-overlay absolute inset-0 flex items-center justify-center\">\r\n          <span class=\"sf-badge-oos px-2.5 py-0.5 text-xs font-medium\">Out of stock</span>\r\n        </div>\r\n      {%- endif -%}\r\n\r\n      {{- - BADGES - -}}\r\n      <div class=\"absolute top-2 left-2 flex flex-col gap-1\">\r\n        {%- if has_discount and in_stock -%}\r\n          <span class=\"sf-badge-sale sf-border-radius px-2.5 py-0.5 text-xs font-medium\">Sale</span>\r\n        {%- endif -%}\r\n        {%- if in_stock and product.track_inventory -%}\r\n          {%- if product.inventory_quantity >= 1 and product.inventory_quantity < 6 -%}\r\n            <span class=\"sf-badge-low-stock sf-border-radius px-2.5 py-0.5 text-xs font-medium\">\r\n              Only {{ product.inventory_quantity }} left\r\n            </span>\r\n          {%- endif -%}\r\n        {%- endif -%}\r\n      </div>\r\n    </div>\r\n\r\n    {{- - CONTENT - -}}\r\n    <div class=\"flex flex-col flex-1 px-4 pt-4 pb-4 gap-3\">\r\n      <div class=\"flex-1 space-y-1\">\r\n        <h3 class=\"sf-heading sf-product-card__name text-base font-normal line-clamp-2\">\r\n          {{ product.name }}\r\n        </h3>\r\n        {%- if product.description -%}\r\n          <p\r\n            class=\"sf-product-card__desc text-xs line-clamp-2\"\r\n            style=\"color: var(--sf-foreground-subtle)\"\r\n          >\r\n            {{ product.description }}\r\n          </p>\r\n        {%- endif -%}\r\n      </div>\r\n\r\n      {{- - PRICE ROW - -}}\r\n      <div class=\"flex items-center justify-between\">\r\n        <div class=\"flex items-center gap-2\">\r\n          <span\r\n            class=\"sf-product-card__price text-base font-light\"\r\n            style=\"color: var(--sf-foreground)\"\r\n          >\r\n            {{ product.price | money: store.currency }}\r\n          </span>\r\n          {%- if has_discount -%}\r\n            <span\r\n              class=\"sf-product-card__compare text-xs line-through\"\r\n              style=\"color: var(--sf-foreground-subtle)\"\r\n            >\r\n              {{ product.compare_at_price | money: store.currency }}\r\n            </span>\r\n            {%- assign price_diff = product.compare_at_price | minus: product.price -%}\r\n            {%- assign discount_pct = price_diff | times: 100 | divided_by: product.compare_at_price | round -%}\r\n            <span\r\n              class=\"sf-product-card__discount-pct text-xs\"\r\n              style=\"color: var(--sf-primary)\"\r\n            >\r\n              -{{ discount_pct }}%\r\n            </span>\r\n          {%- endif -%}\r\n        </div>\r\n        <span\r\n          class=\"sf-pill sf-pill-inactive sf-product-card__view-btn inline-flex items-center gap-1 px-3 py-1 text-xs border\"\r\n          aria-hidden=\"true\"\r\n        >\r\n          View\r\n          <svg\r\n            width=\"10\"\r\n            height=\"10\"\r\n            viewBox=\"0 0 24 24\"\r\n            fill=\"none\"\r\n            stroke=\"currentColor\"\r\n            stroke-width=\"2\"\r\n            stroke-linecap=\"round\"\r\n            stroke-linejoin=\"round\"\r\n          >\r\n            {% raw %}<path d=\"M5 12h14M12 5l7 7-7 7\"/>{% endraw %}\r\n          </svg>\r\n        </span>\r\n      </div>\r\n    </div>\r\n  </article>\r\n</a>\r\n",
  "classic/sections/mission": "{%- assign eyebrow = section.eyebrow | default: 'Our Mission' -%}\r\n{%- assign settings = store.settings -%}\r\n{%- assign headline = store.name -%}\r\n{%- assign statement = store.description -%}\r\n{%- if settings -%}\r\n  {%- if settings.missionHeadline -%}{%- assign headline = settings.missionHeadline -%}{%- endif -%}\r\n  {%- if settings.mission -%}{%- assign statement = settings.mission -%}{%- endif -%}\r\n{%- endif -%}\r\n\r\n<section class=\"sf-mission relative w-full overflow-hidden py-20 md:py-28\">\r\n  <div class=\"sf-mission-fallback absolute inset-0\"></div>\r\n  <div class=\"relative container mx-auto max-w-4xl px-6 text-center\">\r\n    <span class=\"sf-badge-outline inline-flex items-center border px-2.5 py-0.5 text-xs font-medium mb-4\" {% render 'classic/snippets/editable', editing: store.editing, field: 'eyebrow', value: section.eyebrow %}>\r\n      {{ eyebrow }}\r\n    </span>\r\n    <h1 class=\"sf-heading font-bold tracking-tight\" style=\"font-size: clamp(1.875rem, 5vw, 3rem); line-height: 1.1\" {% render 'classic/snippets/editable-setting', editing: store.editing, key: 'missionHeadline', value: settings.missionHeadline %}>\r\n      {{ headline }}\r\n    </h1>\r\n    {%- comment -%}\r\n      Rendered when empty IN THE EDITOR so there is something to click in order to\r\n      write one. A visitor still sees nothing.\r\n    {%- endcomment -%}\r\n    {%- if statement or store.editing -%}\r\n      <p class=\"font-light mt-4 mx-auto max-w-2xl\" style=\"color: var(--sf-foreground-subtle); font-size: clamp(1rem, 2vw, 1.25rem)\" {% render 'classic/snippets/editable-setting', editing: store.editing, key: 'mission', value: settings.mission %}>\r\n        {{ statement }}\r\n      </p>\r\n    {%- endif -%}\r\n  </div>\r\n</section>\r\n",
  "classic/sections/impact": "{%- assign heading = section.heading | default: 'Our Impact' -%}\r\n{%- assign eyebrow = section.eyebrow | default: 'Impact' -%}\r\n{%- assign settings = store.settings -%}\r\n{%- assign stats = null -%}\r\n{%- if settings -%}{%- assign stats = settings.impactStats -%}{%- endif -%}\r\n{%- if stats and stats.size > 0 -%}\r\n<section class=\"sf-impact sf-section-muted py-16 md:py-24\">\r\n  <div class=\"container mx-auto max-w-5xl px-6\">\r\n    <div class=\"mb-10 md:mb-14 text-center\">\r\n      <span class=\"sf-badge-outline inline-flex items-center border px-2.5 py-0.5 text-xs font-medium mb-3\" {% render 'classic/snippets/editable', editing: store.editing, field: 'eyebrow', value: section.eyebrow %}>\r\n        {{ eyebrow }}\r\n      </span>\r\n      <h2 class=\"sf-heading text-3xl md:text-4xl font-light tracking-tight\" {% render 'classic/snippets/editable', editing: store.editing, field: 'heading', value: section.heading %}>{{ heading }}</h2>\r\n    </div>\r\n    <div class=\"grid gap-8 text-center\" style=\"grid-template-columns: repeat(auto-fit, minmax(160px, 1fr))\">\r\n      {%- for stat in stats -%}\r\n        <div class=\"sf-impact-stat space-y-1\" {% render 'classic/snippets/record-anchor', editing: store.editing, list: 'impactStats', index: forloop.index0 %}>\r\n          <div class=\"sf-heading font-bold\" style=\"font-size: clamp(2rem, 5vw, 3rem); line-height: 1\" {% render 'classic/snippets/editable-item', editing: store.editing, list: 'impactStats', index: forloop.index0, key: 'value', value: stat.value %}>{{ stat.value }}</div>\r\n          <div class=\"text-sm uppercase tracking-widest\" style=\"color: var(--sf-foreground-subtle)\" {% render 'classic/snippets/editable-item', editing: store.editing, list: 'impactStats', index: forloop.index0, key: 'label', value: stat.label %}>{{ stat.label }}</div>\r\n        </div>\r\n      {%- endfor -%}\r\n    </div>\r\n  </div>\r\n</section>\r\n{%- endif -%}\r\n",
  "classic/sections/hero": "{%- comment -%}\r\n  ONE shape: the hero is always a list of slides, and a single-image hero is a list\r\n  of one. `slides` is normalised in lib/hero.ts, which is the only place that still\r\n  knows the legacy flat keys (heroTitle/heroImage/…) exist.\r\n\r\n  It used to branch: a carousel path and a single-slide path, with duplicated card\r\n  markup. That meant the hero was editable in one shape and not the other, and any\r\n  hero feature had to be built twice. Now there is one loop, so a slide is editable\r\n  exactly like a program or a campaign — the same editable-item channel.\r\n\r\n  The CTA still asks two SEPARATE questions, which an earlier version conflated:\r\n    store.commerce      does this site sell?        (the vertical -> the copy)\r\n    campaigns.size > 0  is there something to fund? (the data     -> the behaviour)\r\n  An NGO with no campaign yet is still an NGO, and must not be sold \"New Arrivals\".\r\n{%- endcomment -%}\r\n{%- assign is_giving = false -%}\r\n{%- if campaigns and campaigns.size > 0 -%}\r\n  {%- assign is_giving = true -%}\r\n  {%- assign lead_campaign = campaigns[0] -%}\r\n{%- endif -%}\r\n\r\n{%- comment -%}\r\n  `slides` and `authored` come from SECTION_REGISTRY.hero.pickContext (lib/hero.ts),\r\n  which is the only place that knows how a hero is stored. A caller that renders this\r\n  template without them gets an empty <section> rather than a broken one — the loop\r\n  simply runs zero times. That is a contract, and lib/sections.test.ts pins it.\r\n{%- endcomment -%}\r\n{%- assign multi = false -%}\r\n{%- if slides.size > 1 -%}{%- assign multi = true -%}{%- endif -%}\r\n\r\n<section class=\"sf-hero relative w-full overflow-hidden\" style=\"height: 70vh; min-height: 480px\">\r\n  <div class=\"sf-hero__track\" id=\"sf-hero-track\">\r\n    {%- for slide in slides -%}\r\n      {%- comment -%}\r\n        `slide` is what the visitor SEES (defaults substituted in). `authored_slide`\r\n        is what is actually STORED (no defaults). They are different, and the editable\r\n        snippets must report the STORED one: a hero with no title displays the store's\r\n        name, so reporting the rendered value would save \"KFS\" as though the merchant\r\n        had typed it, and \"Donate\" as their button text.\r\n      {%- endcomment -%}\r\n      {%- assign authored_slide = authored[forloop.index0] -%}\r\n      <div\r\n        class=\"sf-hero__slide absolute inset-0 transition-opacity duration-700{% unless forloop.first %} opacity-0 pointer-events-none{% else %} opacity-100{% endunless %}\"\r\n        data-index=\"{{ forloop.index0 }}\"\r\n        {% render 'classic/snippets/record-anchor', editing: store.editing, list: 'heroSlides', index: forloop.index0 %}\r\n      >\r\n        {%- comment -%}\r\n          The image is a BACKGROUND, so the click target is the backdrop itself\r\n          rather than an <img>. Both branches fill the slide, so the fallback is\r\n          equally clickable: that is how a hero with no image ever gets one.\r\n        {%- endcomment -%}\r\n        {%- if slide.image and slide.image != '' -%}\r\n          <img\r\n            src=\"{{ slide.image }}\"\r\n            alt=\"{{ slide.title }}\"\r\n            class=\"w-full h-full object-cover\"\r\n            {% render 'classic/snippets/editable-image', editing: store.editing, list: 'heroSlides', index: forloop.index0, key: 'image', value: authored_slide.image %}\r\n          >\r\n          <div class=\"absolute inset-0\" style=\"background: rgba(0,0,0,0.28)\"></div>\r\n        {%- else -%}\r\n          <div class=\"sf-hero-fallback absolute inset-0\"\r\n            {% render 'classic/snippets/editable-image', editing: store.editing, list: 'heroSlides', index: forloop.index0, key: 'image', value: authored_slide.image %}></div>\r\n        {%- endif -%}\r\n\r\n        <div class=\"absolute inset-0 flex items-end md:items-center\">\r\n          <div class=\"sf-hero__content w-full px-4 pb-16 md:pb-0\" style=\"padding-left: clamp(1rem, 5vw, 3rem)\">\r\n            <div class=\"sf-hero-card max-w-xl space-y-4 p-5 sf-hero__card-animate{% if forloop.first %} sf-hero__card-animate--load{% endif %}\">\r\n              {%- if slide.accent and slide.accent != '' or store.editing -%}\r\n                <span class=\"sf-badge-outline inline-flex items-center border px-2.5 py-0.5 text-xs font-medium\"\r\n                  {% render 'classic/snippets/editable-item', editing: store.editing, list: 'heroSlides', index: forloop.index0, key: 'accent', value: authored_slide.accent %}>{{ slide.accent }}</span>\r\n              {%- endif -%}\r\n\r\n              <h1\r\n                class=\"sf-heading font-bold tracking-tight\"\r\n                style=\"font-size: clamp(1.875rem, 5vw, 3rem); line-height: 1.1\"\r\n                {% render 'classic/snippets/editable-item', editing: store.editing, list: 'heroSlides', index: forloop.index0, key: 'title', value: authored_slide.title %}\r\n              >{{ slide.title }}</h1>\r\n\r\n              {%- if slide.subtitle and slide.subtitle != '' or store.editing -%}\r\n                <p class=\"font-light\" style=\"color: var(--sf-foreground-subtle); font-size: clamp(0.95rem, 2vw, 1.125rem)\"\r\n                  {% render 'classic/snippets/editable-item', editing: store.editing, list: 'heroSlides', index: forloop.index0, key: 'subtitle', value: authored_slide.subtitle %}>{{ slide.subtitle }}</p>\r\n              {%- endif -%}\r\n\r\n              {%- if is_giving -%}\r\n                {%- comment -%} There IS a campaign: the CTA opens the donate flow. {%- endcomment -%}\r\n                <button\r\n                  class=\"sf-btn-primary sf-donate sf-hero__btn inline-flex items-center gap-2 border rounded-none px-6 py-3 text-sm font-medium\"\r\n                  data-campaign-id=\"{{ lead_campaign.id }}\"\r\n                  data-campaign-title=\"{{ lead_campaign.title }}\"\r\n                  data-presets=\"{{ lead_campaign.presets | join: ',' }}\"\r\n                  data-allow-custom=\"{% if lead_campaign.allowCustomAmount == false %}false{% else %}true{% endif %}\"\r\n                >\r\n                  <span {% render 'classic/snippets/editable-item', editing: store.editing, list: 'heroSlides', index: forloop.index0, key: 'buttonText', value: authored_slide.buttonText %}>{{ slide.buttonText }}</span>\r\n                  <svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\r\n                    <path d=\"M5 12h14M12 5l7 7-7 7\"/>\r\n                  </svg>\r\n                </button>\r\n              {%- elsif store.commerce -%}\r\n                {%- comment -%} A shop: scroll to the products on this page. {%- endcomment -%}\r\n                <a\r\n                  href=\"#products\"\r\n                  class=\"sf-btn-primary sf-hero__btn inline-flex items-center gap-2 border rounded-none px-6 py-3 text-sm font-medium\"\r\n                  onclick=\"document.getElementById('products')?.scrollIntoView({behavior:'smooth'}); return false;\"\r\n                >\r\n                  <span {% render 'classic/snippets/editable-item', editing: store.editing, list: 'heroSlides', index: forloop.index0, key: 'buttonText', value: authored_slide.buttonText %}>{{ slide.buttonText }}</span>\r\n                  <svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\r\n                    <path d=\"M5 12h14M12 5l7 7-7 7\"/>\r\n                  </svg>\r\n                </a>\r\n              {%- else -%}\r\n                {%- comment -%}\r\n                  A giving site with no campaign yet. Scrolling to #products would be a\r\n                  dead click (no such section), so send them to what this site DOES have.\r\n                {%- endcomment -%}\r\n                <a\r\n                  href=\"#contact\"\r\n                  class=\"sf-btn-primary sf-hero__btn inline-flex items-center gap-2 border rounded-none px-6 py-3 text-sm font-medium\"\r\n                  onclick=\"document.querySelector('.sf-contact')?.scrollIntoView({behavior:'smooth'}); return false;\"\r\n                >\r\n                  <span {% render 'classic/snippets/editable-item', editing: store.editing, list: 'heroSlides', index: forloop.index0, key: 'buttonText', value: authored_slide.buttonText %}>{{ slide.buttonText }}</span>\r\n                  <svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\r\n                    <path d=\"M5 12h14M12 5l7 7-7 7\"/>\r\n                  </svg>\r\n                </a>\r\n              {%- endif -%}\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    {%- endfor -%}\r\n  </div>\r\n\r\n  {%- if multi -%}\r\n    {{- - DOT INDICATORS — only meaningful with more than one slide - -}}\r\n    <div class=\"absolute bottom-6 flex gap-2 z-30\" style=\"left: 50%; transform: translateX(-50%)\">\r\n      {%- for slide in slides -%}\r\n        <button\r\n          class=\"sf-hero__dot transition-all duration-300 rounded-none border-0 p-0 cursor-pointer{% if forloop.first %} sf-hero__dot--active{% endif %}\"\r\n          data-index=\"{{ forloop.index0 }}\"\r\n          aria-label=\"Go to slide {{ forloop.index }}\"\r\n          style=\"height: 2px; background: {% if forloop.first %}#fff{% else %}rgba(255,255,255,0.35){% endif %}; width: {% if forloop.first %}3rem{% else %}1.5rem{% endif %}\"\r\n        ></button>\r\n      {%- endfor -%}\r\n    </div>\r\n  {%- endif -%}\r\n</section>\r\n\r\n{%- if multi -%}\r\n  <script>\r\n    (function () {\r\n      var slides = document.querySelectorAll('.sf-hero__slide');\r\n      var dots = document.querySelectorAll('.sf-hero__dot');\r\n      if (slides.length < 2) return;\r\n\r\n      var current = 0;\r\n\r\n      function goTo(index) {\r\n        slides[current].classList.remove('opacity-100');\r\n        slides[current].classList.add('opacity-0', 'pointer-events-none');\r\n        dots[current].style.width = '1.5rem';\r\n        dots[current].style.background = 'rgba(255,255,255,0.35)';\r\n\r\n        current = index;\r\n\r\n        slides[current].classList.remove('opacity-0', 'pointer-events-none');\r\n        slides[current].classList.add('opacity-100');\r\n        dots[current].style.width = '3rem';\r\n        dots[current].style.background = '#fff';\r\n\r\n        var card = slides[current].querySelector('.sf-hero__card-animate');\r\n        if (card) {\r\n          card.classList.remove('sf-hero__card-animate--in');\r\n          void card.offsetWidth; // force reflow\r\n          card.classList.add('sf-hero__card-animate--in');\r\n        }\r\n      }\r\n\r\n      dots.forEach(function (dot) {\r\n        dot.addEventListener('click', function () {\r\n          goTo(parseInt(this.dataset.index));\r\n          resetTimer();\r\n        });\r\n      });\r\n\r\n      // Editor handoff: after a slide add/delete/reorder the iframe reloads, and the\r\n      // Editor sets location.hash to the slide the merchant was acting on so the\r\n      // carousel FOLLOWS it instead of snapping back to slide 0. Server-free.\r\n      (function () {\r\n        var m = /(?:^|#|&)slide=(\\d+)/.exec(location.hash || '');\r\n        if (!m) return;\r\n        var n = parseInt(m[1], 10);\r\n        if (n > 0 && n < slides.length) goTo(n);\r\n      })();\r\n\r\n      var firstCard = slides[0].querySelector('.sf-hero__card-animate');\r\n      if (firstCard) {\r\n        setTimeout(function () { firstCard.classList.add('sf-hero__card-animate--in'); }, 80);\r\n      }\r\n\r\n      // In the Editor the carousel must HOLD STILL: auto-advancing would slide the\r\n      // text out from under a merchant halfway through typing it.\r\n      var editing = {% if store.editing %}true{% else %}false{% endif %};\r\n      var timer = editing ? null : setInterval(function () { goTo((current + 1) % slides.length); }, 5000);\r\n\r\n      function resetTimer() {\r\n        if (editing) return;\r\n        clearInterval(timer);\r\n        timer = setInterval(function () { goTo((current + 1) % slides.length); }, 5000);\r\n      }\r\n    })();\r\n  </script>\r\n{%- endif -%}\r\n",
  "classic/sections/featured-products": "{%- assign heading = section.heading | default: 'Top Picks' -%}\r\n{%- assign eyebrow = section.eyebrow | default: 'Featured Collection' -%}\r\n{%- if products and products.size > 0 -%}\r\n<section class=\"py-12 md:py-20\">\r\n  <div class=\"container mx-auto max-w-6xl px-6\">\r\n    {{- - HEADER - -}}\r\n    <div class=\"mb-10 md:mb-14\">\r\n      <div class=\"flex items-center gap-4 mb-3\">\r\n        <div class=\"h-px flex-1\" style=\"background-color: var(--sf-border)\"></div>\r\n        <span class=\"sf-badge-outline inline-flex items-center border px-2.5 py-0.5 text-xs font-medium\" {% render 'classic/snippets/editable', editing: store.editing, field: 'eyebrow', value: section.eyebrow %}>\r\n          {{ eyebrow }}\r\n        </span>\r\n        <div class=\"h-px flex-1\" style=\"background-color: var(--sf-border)\"></div>\r\n      </div>\r\n      <h2 class=\"sf-heading text-3xl md:text-4xl font-light text-center tracking-tight\" {% render 'classic/snippets/editable', editing: store.editing, field: 'heading', value: section.heading %}>{{ heading }}</h2>\r\n    </div>\r\n\r\n    {{- - GRID - -}}\r\n    <div\r\n      class=\"grid gap-4 md:gap-6\"\r\n      style=\"grid-template-columns: repeat(auto-fill, minmax(220px, 1fr))\"\r\n    >\r\n      {%- for product in products -%}\r\n        {%- render 'classic/sections/product-card', store: store, product: product -%}\r\n      {%- endfor -%}\r\n    </div>\r\n\r\n    {{- - VIEW ALL - -}}\r\n    <div class=\"mt-10 flex justify-center\">\r\n      <a\r\n        href=\"/store/{{ store.slug }}/products\"\r\n        class=\"sf-pill sf-pill-inactive border px-8 py-2.5 text-sm inline-flex items-center gap-2 transition-all\"\r\n      >\r\n        View all products\r\n        <svg\r\n          width=\"12\"\r\n          height=\"12\"\r\n          viewBox=\"0 0 24 24\"\r\n          fill=\"none\"\r\n          stroke=\"currentColor\"\r\n          stroke-width=\"2\"\r\n          stroke-linecap=\"round\"\r\n          stroke-linejoin=\"round\"\r\n        >\r\n          {% raw %}<path d=\"M5 12h14M12 5l7 7-7 7\"/>{% endraw %}\r\n        </svg>\r\n      </a>\r\n    </div>\r\n  </div>\r\n</section>\r\n{%- endif -%}\r\n",
  "classic/sections/contact": "{%- assign heading = section.heading | default: 'Contact Us' -%}\r\n{%- assign eyebrow = section.eyebrow | default: 'Get in Touch' -%}\r\n{%- assign settings = store.settings -%}\r\n{%- assign contact = null -%}\r\n{%- assign social = null -%}\r\n{%- if settings -%}\r\n  {%- assign contact = settings.contact -%}\r\n  {%- assign social = settings.socialLinks -%}\r\n{%- endif -%}\r\n\r\n{%- assign has_contact = false -%}\r\n{%- if contact -%}\r\n  {%- if contact.email or contact.phone or contact.address -%}{%- assign has_contact = true -%}{%- endif -%}\r\n{%- endif -%}\r\n{%- assign has_social = false -%}\r\n{%- if social and social.size > 0 -%}{%- assign has_social = true -%}{%- endif -%}\r\n\r\n{%- if has_contact or has_social -%}\r\n<section class=\"sf-contact py-16 md:py-24\">\r\n  <div class=\"container mx-auto max-w-3xl px-6 text-center\">\r\n    <span class=\"sf-badge-outline inline-flex items-center border px-2.5 py-0.5 text-xs font-medium mb-3\" {% render 'classic/snippets/editable', editing: store.editing, field: 'eyebrow', value: section.eyebrow %}>\r\n      {{ eyebrow }}\r\n    </span>\r\n    <h2 class=\"sf-heading text-3xl md:text-4xl font-light tracking-tight mb-8\" {% render 'classic/snippets/editable', editing: store.editing, field: 'heading', value: section.heading %}>{{ heading }}</h2>\r\n    {%- if has_contact -%}\r\n      <div class=\"space-y-2 mb-8\">\r\n        {%- if contact.email -%}\r\n          <p><a href=\"mailto:{{ contact.email }}\" class=\"sf-link\">{{ contact.email }}</a></p>\r\n        {%- endif -%}\r\n        {%- if contact.phone -%}\r\n          <p><a href=\"tel:{{ contact.phone }}\" class=\"sf-link\">{{ contact.phone }}</a></p>\r\n        {%- endif -%}\r\n        {%- if contact.address -%}\r\n          <p style=\"color: var(--sf-foreground-subtle)\">{{ contact.address }}</p>\r\n        {%- endif -%}\r\n      </div>\r\n    {%- endif -%}\r\n    {%- if has_social -%}\r\n      <div class=\"flex justify-center gap-4\">\r\n        {%- for link in social -%}\r\n          <a href=\"{{ link.url }}\" class=\"sf-link text-sm\" target=\"_blank\" rel=\"noopener noreferrer\">{{ link.platform }}</a>\r\n        {%- endfor -%}\r\n      </div>\r\n    {%- endif -%}\r\n  </div>\r\n</section>\r\n{%- endif -%}\r\n",
  "classic/sections/collections-grid": "{%- assign heading = section.heading | default: 'Shop by Category' -%}\r\n{%- assign eyebrow = section.eyebrow | default: 'Collections' -%}\r\n{%- assign subheading = section.subheading | default: 'Curated selections for every need' -%}\r\n{%- if collections and collections.size > 0 -%}\r\n<section class=\"sf-section-muted py-12 md:py-20\">\r\n  <div class=\"container mx-auto max-w-6xl px-6\">\r\n    {{- - HEADER - -}}\r\n    <div class=\"mb-10 md:mb-14\">\r\n      <span class=\"sf-badge-outline inline-flex items-center border px-2.5 py-0.5 text-xs font-medium mb-3\" {% render 'classic/snippets/editable', editing: store.editing, field: 'eyebrow', value: section.eyebrow %}>\r\n        {{ eyebrow }}\r\n      </span>\r\n      <h2 class=\"sf-heading text-3xl md:text-4xl font-light tracking-tight\" {% render 'classic/snippets/editable', editing: store.editing, field: 'heading', value: section.heading %}>{{ heading }}</h2>\r\n      <p class=\"font-light text-sm mt-2\" style=\"color: var(--sf-foreground-subtle)\">\r\n        {{ subheading }}\r\n      </p>\r\n    </div>\r\n\r\n    {{- - FILTER PILLS - -}}\r\n    <div\r\n      class=\"sf-collections__pills flex gap-2 overflow-x-auto pb-4 mb-8\"\r\n      style=\"-webkit-overflow-scrolling: touch; scrollbar-width: none\"\r\n    >\r\n      <button\r\n        class=\"sf-pill sf-pill-active sf-collections__pill shrink-0 px-4 py-1.5 text-sm border transition-colors\"\r\n        data-collection=\"all\"\r\n        onclick=\"sfFilterCollection(this, 'all')\"\r\n      >\r\n        All\r\n      </button>\r\n      {%- for collection in collections -%}\r\n        <button\r\n          class=\"sf-pill sf-pill-inactive sf-collections__pill shrink-0 px-4 py-1.5 text-sm border transition-colors\"\r\n          data-collection=\"{{ collection.id }}\"\r\n          onclick=\"sfFilterCollection(this, '{{ collection.id }}')\"\r\n        >\r\n          {{ collection.name }}\r\n        </button>\r\n      {%- endfor -%}\r\n    </div>\r\n\r\n    {{- - GRID - -}}\r\n    <div\r\n      class=\"grid gap-6 md:gap-8\"\r\n      style=\"grid-template-columns: repeat(auto-fill, minmax(280px, 1fr))\"\r\n    >\r\n      {%- for collection in collections -%}\r\n        <article\r\n          class=\"sf-card sf-collection-card group cursor-pointer overflow-hidden sf-animate-fadein\"\r\n          data-collection-id=\"{{ collection.id }}\"\r\n          onclick=\"window.location.href='/store/{{ store.slug }}/collections/{{ collection.slug }}'\"\r\n        >\r\n          {{- - IMAGE - -}}\r\n          <div class=\"relative overflow-hidden sf-bg-muted sf-collection-card__image-wrap\">\r\n            {%- if collection.image_url -%}\r\n              <img\r\n                src=\"{{ collection.image_url }}\"\r\n                alt=\"{{ collection.name }}\"\r\n                loading=\"lazy\"\r\n                class=\"sf-collection-card__image absolute inset-0 w-full h-full object-cover\"\r\n              >\r\n            {%- else -%}\r\n              <div class=\"sf-collection-placeholder w-full h-full\"></div>\r\n            {%- endif -%}\r\n\r\n            {{- - HOVER OVERLAY - -}}\r\n            <div class=\"sf-collection-card__overlay absolute inset-0 flex items-end p-4\">\r\n              <span\r\n                class=\"sf-collection-card__cta text-xs uppercase tracking-widest font-medium\"\r\n                style=\"color: #fff; border-bottom: 1px solid rgba(255,255,255,0.5); padding-bottom: 2px\"\r\n              >\r\n                Explore collection →\r\n              </span>\r\n            </div>\r\n          </div>\r\n\r\n          {{- - CONTENT - -}}\r\n          <div class=\"px-4 pt-4 pb-4 space-y-1\">\r\n            <h3 class=\"sf-heading text-xl font-light sf-collection-card__name\">\r\n              {{ collection.name }}\r\n            </h3>\r\n            {%- if collection.description -%}\r\n              <p class=\"line-clamp-2 text-sm\" style=\"color: var(--sf-foreground-subtle)\">\r\n                {{ collection.description }}\r\n              </p>\r\n            {%- endif -%}\r\n          </div>\r\n        </article>\r\n      {%- endfor -%}\r\n    </div>\r\n    {{- - VIEW ALL - -}}\r\n    <div class=\"mt-10 flex justify-center\">\r\n      <a\r\n        href=\"/store/{{ store.slug }}/products\"\r\n        class=\"sf-pill sf-pill-inactive border px-8 py-2.5 text-sm inline-flex items-center gap-2 transition-all\"\r\n      >\r\n        Browse all products\r\n        <svg\r\n          width=\"12\"\r\n          height=\"12\"\r\n          viewBox=\"0 0 24 24\"\r\n          fill=\"none\"\r\n          stroke=\"currentColor\"\r\n          stroke-width=\"2\"\r\n          stroke-linecap=\"round\"\r\n          stroke-linejoin=\"round\"\r\n        >\r\n          {% raw %}<path d=\"M5 12h14M12 5l7 7-7 7\"/>{% endraw %}\r\n        </svg>\r\n      </a>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<script>\r\n  (function () {\r\n    function sfFilterCollection(btn, collectionId) {\r\n      // update pill states\r\n      var pills = document.querySelectorAll('.sf-collections__pill');\r\n      pills.forEach(function (p) {\r\n        p.classList.remove('sf-pill-active');\r\n        p.classList.add('sf-pill-inactive');\r\n      });\r\n      btn.classList.remove('sf-pill-inactive');\r\n      btn.classList.add('sf-pill-active');\r\n\r\n      // show/hide cards\r\n      var cards = document.querySelectorAll('.sf-collection-card');\r\n      cards.forEach(function (card) {\r\n        if (collectionId === 'all' || card.dataset.collectionId === collectionId) {\r\n          card.style.display = '';\r\n        } else {\r\n          card.style.display = 'none';\r\n        }\r\n      });\r\n    }\r\n\r\n    // expose to onclick handlers\r\n    window.sfFilterCollection = sfFilterCollection;\r\n  })();\r\n</script>\r\n{%- endif -%}\r\n",
  "classic/sections/campaigns": "{%- assign heading = section.heading | default: 'Support a Cause' -%}\r\n{%- assign eyebrow = section.eyebrow | default: 'Campaigns' -%}\r\n{%- if campaigns and campaigns.size > 0 -%}\r\n<section class=\"sf-campaigns py-16 md:py-24\">\r\n  <div class=\"container mx-auto max-w-5xl px-6\">\r\n    <div class=\"mb-10 md:mb-14 text-center\">\r\n      <span class=\"sf-badge-outline inline-flex items-center border px-2.5 py-0.5 text-xs font-medium mb-3\" {% render 'classic/snippets/editable', editing: store.editing, field: 'eyebrow', value: section.eyebrow %}>\r\n        {{ eyebrow }}\r\n      </span>\r\n      <h2 class=\"sf-heading text-3xl md:text-4xl font-light tracking-tight\" {% render 'classic/snippets/editable', editing: store.editing, field: 'heading', value: section.heading %}>{{ heading }}</h2>\r\n    </div>\r\n    <div class=\"space-y-8\">\r\n      {%- for c in campaigns -%}\r\n        <article class=\"sf-card sf-campaign-card overflow-hidden md:flex\" {% render 'classic/snippets/record-anchor', editing: store.editing, list: 'campaigns', index: forloop.index0 %}>\r\n          {%- comment -%}\r\n            Liquid treats \"\" as truthy, so a blank image field would render\r\n            <img src=\"\"> and the browser draws a broken image.\r\n          {%- endcomment -%}\r\n          {%- if c.image and c.image != '' -%}\r\n            <div class=\"relative sf-bg-muted md:w-2/5\" style=\"aspect-ratio: 16/9\"\r\n              {% render 'classic/snippets/editable-image', editing: store.editing, list: 'campaigns', index: forloop.index0, key: 'image', value: c.image %}>\r\n              <img src=\"{{ c.image }}\" alt=\"{{ c.title }}\" loading=\"lazy\" class=\"absolute inset-0 w-full h-full object-cover\">\r\n            </div>\r\n          {%- elsif store.editing -%}\r\n            {%- comment -%}\r\n              No image yet: a visitor sees nothing, the editor gets a target to click.\r\n            {%- endcomment -%}\r\n            <div class=\"relative sf-bg-muted md:w-2/5\" style=\"aspect-ratio: 16/9\"\r\n              {% render 'classic/snippets/editable-image', editing: store.editing, list: 'campaigns', index: forloop.index0, key: 'image', value: c.image %}></div>\r\n          {%- endif -%}\r\n          <div class=\"p-5 md:flex-1 space-y-3\">\r\n            <h3 class=\"sf-heading text-2xl font-light\" {% render 'classic/snippets/editable-item', editing: store.editing, list: 'campaigns', index: forloop.index0, key: 'title', value: c.title %}>{{ c.title }}</h3>\r\n            {%- if c.description or store.editing -%}\r\n              <p class=\"text-sm\" style=\"color: var(--sf-foreground-subtle)\" {% render 'classic/snippets/editable-item', editing: store.editing, list: 'campaigns', index: forloop.index0, key: 'description', value: c.description %}>{{ c.description }}</p>\r\n            {%- endif -%}\r\n            {%- if c.hasGoal -%}\r\n              <div class=\"sf-campaign-progress space-y-1\">\r\n                <div class=\"w-full h-2 sf-bg-muted overflow-hidden\">\r\n                  <div class=\"sf-campaign-bar h-full\" style=\"width: {{ c.percent }}%\"></div>\r\n                </div>\r\n                <div class=\"flex justify-between text-xs\" style=\"color: var(--sf-foreground-subtle)\">\r\n                  <span>{{ c.raisedLabel }} raised</span>\r\n                  <span>of {{ c.goalLabel }}</span>\r\n                </div>\r\n              </div>\r\n            {%- endif -%}\r\n            <button\r\n              class=\"sf-btn-primary sf-donate border rounded-none px-6 py-2.5 text-sm font-medium\"\r\n              data-campaign-id=\"{{ c.id }}\"\r\n              data-campaign-title=\"{{ c.title }}\"\r\n              data-presets=\"{{ c.presets | join: ',' }}\"\r\n              data-allow-custom=\"{% if c.allowCustomAmount == false %}false{% else %}true{% endif %}\"\r\n            >\r\n              Donate\r\n            </button>\r\n          </div>\r\n        </article>\r\n      {%- endfor -%}\r\n    </div>\r\n  </div>\r\n</section>\r\n{%- endif -%}\r\n",
  "classic/sections/all-products": "{%- assign heading = section.heading | default: 'Browse Everything' -%}\r\n{%- assign eyebrow = section.eyebrow | default: 'All Products' -%}\r\n{{- - ALL PRODUCTS - -}}\r\n<section id=\"products\" class=\"py-12 md:py-20\">\r\n  <div class=\"container mx-auto max-w-6xl px-6\">\r\n    <div class=\"mb-10 md:mb-14\">\r\n      <div class=\"flex items-center gap-4 mb-3\">\r\n        <div class=\"h-px flex-1\" style=\"background-color: var(--sf-border)\"></div>\r\n        <span class=\"sf-badge-outline inline-flex items-center border px-2.5 py-0.5 text-xs font-medium\" {% render 'classic/snippets/editable', editing: store.editing, field: 'eyebrow', value: section.eyebrow %}>\r\n          {{ eyebrow }}\r\n        </span>\r\n        <div class=\"h-px flex-1\" style=\"background-color: var(--sf-border)\"></div>\r\n      </div>\r\n      <h2 class=\"sf-heading text-3xl md:text-4xl font-light text-center tracking-tight\" {% render 'classic/snippets/editable', editing: store.editing, field: 'heading', value: section.heading %}>{{ heading }}</h2>\r\n    </div>\r\n\r\n    {%- if products and products.size > 0 -%}\r\n      <div\r\n        class=\"grid gap-4 md:gap-6\"\r\n        style=\"grid-template-columns: repeat(auto-fill, minmax(220px, 1fr))\"\r\n      >\r\n        {%- for product in products -%}\r\n          {%- render 'classic/sections/product-card', store: store, product: product -%}\r\n        {%- endfor -%}\r\n      </div>\r\n    {%- else -%}\r\n      <div class=\"text-center py-24 space-y-3\">\r\n        <svg\r\n          class=\"mx-auto\"\r\n          width=\"40\"\r\n          height=\"40\"\r\n          viewBox=\"0 0 24 24\"\r\n          fill=\"none\"\r\n          stroke=\"currentColor\"\r\n          stroke-width=\"1.5\"\r\n          stroke-linecap=\"round\"\r\n          stroke-linejoin=\"round\"\r\n          style=\"color: var(--sf-foreground); opacity: 0.2\"\r\n        >\r\n          <path d=\"M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z\"/>\r\n          <path d=\"M3 6h18\"/>\r\n          <path d=\"M16 10a4 4 0 0 1-8 0\"/>\r\n        </svg>\r\n        <p class=\"text-sm\" style=\"color: var(--sf-foreground-subtle)\">No products yet</p>\r\n      </div>\r\n    {%- endif -%}\r\n  </div>\r\n</section>\r\n\r\n{{- - SCROLL FADE-IN OBSERVER - -}}\r\n<script>\r\n  (function () {\r\n    var els = document.querySelectorAll('.sf-animate-fadein');\r\n    if (!els.length) return;\r\n    var io = new IntersectionObserver(\r\n      function (entries) {\r\n        entries.forEach(function (e) {\r\n          if (e.isIntersecting) {\r\n            e.target.classList.add('sf-visible');\r\n            io.unobserve(e.target);\r\n          }\r\n        });\r\n      },\r\n      { threshold: 0.08 }\r\n    );\r\n    els.forEach(function (el) {\r\n      io.observe(el);\r\n    });\r\n  })();\r\n</script>\r\n",
};
